/// MAINFILE
fn p_mainfile(state: &mut ProgramState) {
    println!("{}", "Loading sample data file.");
    p_loadfile(state);
    println!("{}", "Sample data file load complete.");
    p_list_file(state);
    p_list_phone(state);
    p_delseq_file(state);
    p_list_phone(state);
    p_loadfile(state);
    p_list_phone(state);
    p_delprv_file(state);
    p_list_phone(state);
    { let _ = state._fh_tspfile.close();
        std::process::exit(0); }
}

/// LOADFILE
fn p_loadfile(state: &mut ProgramState) {
    tspfile_open_output(state);
    if ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string()) && ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "05".to_string()) {
        // SKIP: unresolved ref
        // SKIP: unresolved display ref
        { let _ = state._fh_tspfile.close();
            std::process::exit(0); }
    }
    p_1000_load_record(state);
}

/// MAX-SUB
fn p_max_sub(state: &mut ProgramState) {
    tspfile_close(state);
}

/// DEL-FILE
fn p_del_file(state: &mut ProgramState) {
    println!("{}{}", "Rewrite sample data file: ", state.cust_stat);
    tspfile_open_io(state);
    if ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string()) && ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "05".to_string()) {
        // SKIP: unresolved ref
        // SKIP: unresolved display ref
        { let _ = state._fh_tspfile.close();
            std::process::exit(0); }
    }
    state.cm_cust_num = "DEL00000".into();
    tspfile_read(state);
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string() {
        println!("{}{}{}{}", "Error ", state.cust_stat, " read lock ", state.cm_cust_num);
    }
    // DELETE TSPFILE
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string() {
        println!("{}{}{}{}", "Error ", state.cust_stat, " delete ", state.cm_cust_num);
    }
    state.cm_cust_num = "INC00000".into();
    tspfile_read(state);
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string() {
        println!("{}{}{}{}", "Error ", state.cust_stat, " read lock ", state.cm_cust_num);
    }
    // DELETE TSPFILE
    if { let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string() {
        println!("{}{}{}{}", "Error ", state.cust_stat, " delete ", state.cm_cust_num);
    }
    println!("{}", "Sample data file rewrite complete.");
    tspfile_close(state);
}

/// DELSEQ-FILE
