    println!("{}", "Test Read/Delete");
    {
        let _bytes = b"00";
        let _len = _bytes.len();
        if _len > 0 { let _end = _len.min(0+2); let _s = String::from_utf8_lossy(&_bytes[0.._end]).trim().to_string(); state.cust_stat.stat_1 = _s.parse().unwrap_or_default(); }
    }
