/// 1000-LOAD-RECORD
fn p_1000_load_record(state: &mut ProgramState) {
    state.tspfl_record = Default::default();
    state.cm_cust_num = FixedString::copy_from(&state.test_data.data_cust_num[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.work_area.tspfl_key = FixedString::copy_from(&state.cm_cust_num);
    state.cm_company = FixedString::copy_from(&state.test_data.data_company[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.cm_address_1 = FixedString::copy_from(&state.test_data.data_address_1[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.cm_address_2 = FixedString::copy_from(&state.test_data.data_address_2[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.cm_address_3 = FixedString::copy_from(&state.test_data.data_address_3[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.cm_telephone = state.test_data.data_telephone[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)];
    state.cm_dp_mgr = FixedString::copy_from(&state.test_data.data_dp_mgr[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.cm_machine = FixedString::copy_from(&state.test_data.data_machine[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]);
    state.cm_no_terminals = format!("{}", state.test_data.data_no_terminals[((state.work_area.sub.trimmed().parse::<i64>().unwrap_or(1) - 1) as usize).min(0)]).trim().parse::<u32>().unwrap_or(0);
    if state.work_area.sub == "" {
        state.cm_disk = "8417".into();
        state.cm_tape = "1600 BPI".into();
        state.cm_memory = "1MEG".into();
    } else {
        state.cm_disk = "8470".into();
        state.cm_tape = "6250 BPI".into();
        state.cm_memory = "3MEG".into();
        if state.work_area.sub == "" {
            state.cm_disk = FixedString::from_cobol_str(&format!("{}", "*"));
            state.cm_tape = FixedString::from_cobol_str(&format!("{}", "*"));
            tspfl_record_write(state);
            if ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string()) && ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "02".to_string()) {
                println!("{}{}{}{}", "WRITE: ", state.work_area.tspfl_key, ", Status: ", state.cust_stat);
            }
        }
    }
}

